function ModelCrossWar:CrossWarTempleInfoResp(pb)
    self.selfInsideInfo = {}
    self.freeChallengeNum = pb.freeChallengeCnt
    self.buyChallengeNum = pb.buyChallengeCnt
    self.challengeNum = pb.challengeCnt
    self.innerTempleInfo = {
        innerTempleRank = pb.innerTempleInfo.innerTempleRank,
        applyInfoList = self:ParseInnerTempleMasterInfo(pb.innerTempleInfo.applyInfoList),
        approvalList = self:ParseInnerTempleApplyInfo(pb.innerTempleInfo.approvalList),
        recruitTime = pb.innerTempleInfo.recruitTime
    }
    self:ParseInnerTemplePlayerInfo(pb.innerTempleInfo.playerInfoList)
    self.setting = {
        approvalLv = pb.setting.approvalLv,
        isGuild = pb.setting.isGuild,
        isServer = pb.setting.isServer,
        isFriend = pb.setting.isFriend,
    }
    FireEvent("CrossWarTempleInfoResp")
end

function ModelCrossWar:CrossWarTempleStateResp(pb)
    self.state = pb.state
    self.settleTime = pb.settleTime
    self.endSettleTime = pb.endSettleTime
    self.endTime = pb.endTime

    if self.state == 0 or self.state == 3 then
        for _, v in ipairs(self.wndList) do
            GF.CloseWndByName(v)
        end
    end
    if self.state == 2 then
        GF.CloseWndByName("UIKuafuWarInside")
    end
    FireEvent("CrossWarTempleStateResp")
end

