function ModelCrossWar:CrossWarTempleRetinueApplyResp(pb)
    local type = pb.type
    self.retinueEndTime = pb.endTime
    self.retinueRewards = {}
    for _, v in ipairs(pb.rewardInfo) do
        local data = {}
        data.type = v.type
        data.refId = v.itemId
        data.count = v.count
        data.bEff = v.effect
        table.insert(self.retinueRewards, data)
    end

    self:ClearPlayerList()
    gModelCrossWar:CrossWarTempleInfoReq()

    if type == 4 then
        GF.OpenWndBottom("UIOutts", { childIndex = 2 })
        GF.OpenWndBottom("UIKuafuWar")
        GF.OpenWndBottom("UIKuafuWarInside")
    end
    FireEvent("CrossWarTempleRetinueApplyResp")
end

