function ModelCrossWar:CrossWarTempleBattleRecordResp(pb)
    self.recordInfos = {}
    for _, v in ipairs(pb.recordInfos) do
        local data = {}
        local playerInfo = StructPlayerInfo:New()
        playerInfo:CreateByPb(v.roleInfo)
        data.playerInfo = playerInfo
        data.power = v.power
        data.reportUrl = v.reportUrl
        data.battleResult = v.battleResult  --1挑战成功 2挑战失败 3防守成功 4防守失败
        data.rankChange = v.rankChange
        data.npcId = v.npcId  --0为玩家
        data.newRank = v.newRank
        data.serverId = v.serverId
        table.insert(self.recordInfos, data)
    end
    FireEvent("CrossWarTempleBattleRecordResp")
end

function ModelCrossWar:CrossWarTempleChallengeListResp(pb)
    self.challengeList = {}
    self.selfOutsideInfo = {}
    for _, v in ipairs(pb.challengeList) do
        local data = {}
        local playerInfo = StructPlayerInfo:New()
        if v.npcId == 0 then
            playerInfo:CreateByPb(v.info)
        end
        data.playerInfo = playerInfo
        data.rank = v.rank
        data.npcId = v.npcId
        data.power = v.power
        table.insert(self.challengeList, data)
        if v.info and v.info.playerId == gModelPlayer:GetPlayerId() then
            self.selfOutsideInfo = data
        end
    end
    FireEvent("CrossWarTempleChallengeListResp")
end

function ModelCrossWar:CrossWarTempleRetinueRecruitResp(pb)
    if not self.innerTempleInfo then
        self.innerTempleInfo = {}
    end
    self.innerTempleInfo.recruitTime = pb.recruitTime
end

function ModelCrossWar:CrossWarTempleGroupInfoResp(pb)
    local list = {}
    for i, v in ipairs(pb.serverNames) do
        table.insert(list, {
            serverName = v,
            serverId = pb.serverIds[i]
        })
    end
    if #list <= 0 then
        GF.ShowMessage(ccClientText(17983))
        return
    end
    GF.OpenWnd("UIKfSyerGroupingPop",{
        wndType = 6,
        groupId = pb.groupId,
        serverList = list
    })
end

