function ModelCrossWar:GetChallengeMoneyData()
    if not self.challengeMoneyData then
        self.challengeMoneyData = {}
        local s = GameTable.BattleTempleConfigRef.challengeNumConsume1
        local data = string.split(s, ";")
        for _, v in ipairs(data) do
