---handle
function ModelCrossWar:ParseInnerTempleMasterInfo(pb)
    local data = {}
    self.applyNum = 0
    if not table.isempty(pb) then
        for _, v in ipairs(pb) do
            local data2 = {}
            local playerInfo = StructPlayerInfo:New()
            playerInfo:CreateByPb(v.info)
            data2.playerInfo = playerInfo
            data2.retinueNum = v.retinueNum
            data2.followNum = v.followNum
            data2.rank = v.rank
            data2.power = v.power
            data2.retinueStatus = v.retinueStatus
            table.insert(data, data2)
    
            self.applyNum = self.applyNum + v.retinueStatus
        end
    end
    return data
end

function ModelCrossWar:ParseInnerTemplePlayerInfo(pb)
    if not self.innerTempleInfo then
        self.innerTempleInfo = {}
    end
    if not self.innerTempleInfo.playerInfoList then
        self.innerTempleInfo.playerInfoList = {}
    end
    local waitResetList = {true, true, true}
    local list = self.innerTempleInfo.playerInfoList

    local selfId = gModelPlayer:GetPlayerId()
    if not table.isempty(pb) then
        for _, v in ipairs(pb) do
            if waitResetList[v.roleType] then
                list[v.roleType] = {}
                waitResetList[v.roleType] = false
            end
            local data = {}
            local playerInfo = StructPlayerInfo:New()
            playerInfo:CreateByPb(v.info)
            data.playerInfo = playerInfo
            data.roleType = v.roleType
            data.power = v.power
            data.endTime = v.endTime

            table.insert(list[v.roleType], data)

            if v.info.playerId == selfId then
                self.selfInsideInfo = data
            end
        end
    end
    if table.isempty(self.selfInsideInfo) then
        GF.CloseWndByName("UIKuafuWarInside")
    end
    self.innerTempleInfo.playerInfoList = list
end

function ModelCrossWar:ParseInnerTempleApplyInfo(pb)
    local data = {}
    if not table.isempty(pb) then
        for _, v in ipairs(pb) do
            local data2 = {}
            local playerInfo = StructPlayerInfo:New()
            playerInfo:CreateByPb(v.info)
            data2.playerInfo = playerInfo
            data2.power = v.power
            data2.applyTime = v.applyTime
            table.insert(data, data2)
        end
    end
    return data
end

function ModelCrossWar:ClearPlayerList()
    if self.innerTempleInfo then
        self.innerTempleInfo.playerInfoList = {}
    end
end

return ModelCrossWar